function Write-Utf8NoBom {
  param([string]$Path, [string]$Content)
  $enc = [System.Text.UTF8Encoding]::new($false)
  [System.IO.File]::WriteAllText($Path, $Content.TrimStart("`r", "`n"), $enc)
}

